def molecule_to_binary(molecule: str) -> str:
    atomic_weights = {
        'H': 1,
        'C': 12,
        'O': 16
    }

    binary_code = ''
    i = 0

    while i < len(molecule):
        if molecule[i].isalpha():
            symbol = molecule[i]
            weight = atomic_weights.get(symbol, 0)
            binary_code += bin(ord(symbol))[2:]
            i += 1
        else:
            count = int(molecule[i])
            last_char = ''
            j = i + 1

            while j < len(molecule) and not molecule[j].isalpha():
                j += 1

            if j < len(molecule):
                last_char = molecule[j]
                binary_code += bin(ord(last_char))[2:]
                weight = atomic_weights.get(last_char, 0)

            for _ in range(count - 1):
                binary_code += bin(weight)[2:]

            i = j + 1
    return '0b' + binary_code
